mapper.update:
UPDATE TB_TRANSFER_LIMIT
SET DAILY_LIMIT = #{dailyLimit},
    CHANGE_REASON = #{changeReason}
WHERE CUSTOMER_NO = #{customerNo}
  AND STATUS = 'ACTIVE'

mapper.select:
SELECT COUNT(1)
FROM TB_AUTO_DEBIT
WHERE WITHDRAW_ACCOUNT_NO = #{withdrawAccountNo}
  AND PAYER_NO = #{payerNo}
  AND STATUS = 'ACTIVE'

SELECT COUNT(1)
FROM TB_CORPORATE_USER
WHERE BUSINESS_NO = #{businessNo}
  AND USER_ID = #{userId}
  AND STATUS = 'ACTIVE'
